package be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.TussenkomstManager;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.OpdrachtAardKodeExtensieKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.SleutelTussenkomstBedrag;
import be.schaubroeck.lpb.tools.SleutelTussenkomstHoofd;
import be.schaubroeck.lpb.tools.SleutelTussenkomstLijn;
import be.schaubroeck.lpb.tools.enumtypes.AardRekenelement;
import be.schaubroeck.lpb.tools.enumtypes.RekenHoofdBron;
import be.schaubroeck.lpb.tools.enumtypes.Rekengroep;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.jpa.lo.RekenBedragPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenHoofdPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenLijnPO;
import com.google.common.collect.Ordering;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.Collection;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SLEUTEL_TUSSENKOMSTEN;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.TUSSENKOMST_MANAGER_KEY;

public class DoeSleutelTussenkomst extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);

        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);

        Collection<SleutelTussenkomstHoofd> sleutelTussenkomsten = tussenkomstManager.getSleutelTussenkomsten();
        List<RekenHoofd> rekenHoofden = new ArrayList<>();
        for (SleutelTussenkomstHoofd sleutelTussenkomst : sleutelTussenkomsten) {
            RekenHoofd rekenHoofd = maakRekenHoofd(sleutelTussenkomst, rekenTijd);

            for (SleutelTussenkomstLijn lijn : sleutelTussenkomst.getLijnen()) {
                Set<RekenBedrag> bedragen = vormRekenBedragen(lijn.getBedragen());
                RekenLijn rekenLijn = maakRekenLijn(lijn, bedragen);
                rekenHoofd.addRekenLijn(rekenLijn);
            }
            rekenHoofden.add(rekenHoofd);
        }
        mainContext.put(SLEUTEL_TUSSENKOMSTEN, rekenHoofden);
        controleTussenkomstOpZeroProperty(mainContext, rekenHoofden);
        return CONTINUE_PROCESSING;
    }

    private void controleTussenkomstOpZeroProperty(RekenContext mainContext, List<RekenHoofd> rekenHoofden) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        LoonElementManager loonElementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);
        for (RekenHoofd rekenHoofd : rekenHoofden) {
            Opdracht opdracht = RekenTools.findOpdracht(persoon, rekenHoofd.getOpdracht().getId());
            for (RekenLijn rekenLijn : rekenHoofd.getRekenLijnen()) {
                LocalDate selectieDatum = Ordering.natural().min(opdracht.getEindDatum(), rekenLijn.getEindDatum());
                Opper opper = RekenTools.findOpper(opdracht, selectieDatum);
                LoonElement loonElement = loonElementManager.getLoonElement(rekenLijn.getAardKodeExtensie(), opper, rekenLijn.getReferentieJaar());
                for (RekenBedrag rekenBedrag : rekenLijn.getRekenBedragen()) {
                    MoneyKey moneyKey =
                            RekenTools.bedragTypeToMoneyKey(rekenBedrag.getBedragType(), rekenLijn.getRegimeBv(), rekenHoofd.getBeginDatum());
                    if ((loonElement == null || loonElement.getPropertyMoney(moneyKey).signum() == 0) && rekenBedrag.getBedrag().signum() != 0) {
                        OpdrachtAardKodeExtensieKey sleutel = new OpdrachtAardKodeExtensieKey(opdracht, rekenLijn.getAardKodeExtensie());
                        tussenkomstManager.sleutelTussenkomstOpZeroProperty(sleutel, moneyKey);
                    }

                }
            }
        }
    }

    private RekenHoofd maakRekenHoofd(SleutelTussenkomstHoofd hoofd, RekenTijd rekenTijd) {
        LocalDate beginDatum = rekenTijd.beginDatum;

        RekenHoofd rekenHoofd = new RekenHoofdPO();
        rekenHoofd.setOpdracht(hoofd.getOpdracht());
        rekenHoofd.setBeginDatum(beginDatum);
        rekenHoofd.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        rekenHoofd.setRekenTijdstip(rekenTijd.rekenTijdstip);
        rekenHoofd.setRekenDatum(rekenTijd.rekenDatum);
        rekenHoofd.setBeslagDatum(hoofd.getBeslagDatum());
        rekenHoofd.setJaar(beginDatum.getYear());
        rekenHoofd.setKwartaal(TimeTools.bepaalKwartaal(beginDatum));
        rekenHoofd.setFiscaalJaar(beginDatum.getYear());
        rekenHoofd.setAchterstal(rekenTijd.rekenDatum.getYear() > beginDatum.getYear());
        rekenHoofd.setRekenModus(Rekenmodus.NORMAAL);

        rekenHoofd.setRekenGroep(Rekengroep.NULL);
        rekenHoofd.setHoedanigheid(hoofd.getHoedanigheid());
        rekenHoofd.setCategorie(hoofd.getCategorie());
        rekenHoofd.setWerkgeversCategorie(hoofd.getWerkgeversCategorie());
        rekenHoofd.setWerknemersKengetal(hoofd.getWerknemersKengetal());
        rekenHoofd.setPensioenStelsel(hoofd.getPensioenStelsel());
        rekenHoofd.setBron(RekenHoofdBron.CONVERSIE);
        return rekenHoofd;
    }

    private RekenLijn maakRekenLijn(SleutelTussenkomstLijn sleutelTussenkomstLijn, Set<RekenBedrag> rekenBedragen) {
        RekenLijn lijn = new RekenLijnPO();
        lijn.setBeginDatum(sleutelTussenkomstLijn.getBeginDatum());
        lijn.setEindDatum(sleutelTussenkomstLijn.getEindDatum());
        lijn.setAardKodeExtensie(sleutelTussenkomstLijn.getAardKodeExtensie());
        lijn.setRegimeBv(sleutelTussenkomstLijn.getRegimeBv());
        lijn.setRekenBedragen(rekenBedragen);
        lijn.setRekenInfos(new HashSet<>());
        lijn.setReferentieJaar(sleutelTussenkomstLijn.getReferentieJaar());
        lijn.setTypeBoeking(AardRekenelement.SALDO);
        return lijn;
    }

    private RekenBedrag maakRekenBedrag(SleutelTussenkomstBedrag sleutelTussenkomstBedrag) {
        RekenBedrag rekenBedrag = new RekenBedragPO();
        rekenBedrag.setBedragType(sleutelTussenkomstBedrag.getBedragType());
        rekenBedrag.setBedrag(sleutelTussenkomstBedrag.getBedrag());
        return rekenBedrag;
    }

    private Set<RekenBedrag> vormRekenBedragen(Collection<SleutelTussenkomstBedrag> sleutelTussenkomstBedragen) {
        Set<RekenBedrag> rekenBedragen = new HashSet<>();
        for (SleutelTussenkomstBedrag sleutelTussenkomstBedrag : sleutelTussenkomstBedragen) {
            RekenBedrag rekenBedrag = maakRekenBedrag(sleutelTussenkomstBedrag);
            rekenBedragen.add(rekenBedrag);
        }
        return rekenBedragen;
    }

}
